def kth_ordered(words, k):
    if not words or k <= 0:
        return None

    # Group words by their length in descending order of lengths
    length_to_words = {}
    for word in words:
        length = len(word)
        if length not in length_to_words:
            length_to_words[length] = []
        length_to_words[length].append(word)

    # Sort each group reverse-alphabetically
    for words_list in length_to_words.values():
        words_list.sort(reverse=True)

    # Flatten the dictionary to a list of words and sort by increasing length
    sorted_words = sorted([word for word_list in length_to_words.values() for word in word_list])

    if k > len(sorted_words):
        return None

    return sorted_words[k - 1]
